// Analyze sailing conditions in 8 compass directions from a given position
async function getDirections(c) {
  const lat = parseFloat(c.req.query('lat'));
  const lon = parseFloat(c.req.query('lon'));

  // Validate coordinates
  if (isNaN(lat) || isNaN(lon)) {
    return c.json({ error: true, message: 'lat and lon query parameters are required' }, 400);
  }
  if (lat < -90 || lat > 90 || lon < -180 || lon > 180) {
    return c.json({ error: true, message: 'Invalid coordinates: lat must be -90..90, lon must be -180..180' }, 400);
  }

  try {
    const analysis = await functions.call('analyzeDirections', lat, lon);
    return c.json(analysis);
  } catch (err) {
    log.error('Direction analysis failed: ' + err.message);
    return c.json({ error: true, message: 'Failed to analyze directions' }, 500);
  }
}
